+        return BTreeMap::new();
+    };
+
+    let Ok(manifest): Result<ProvenanceManifest, _> = serde_json::from_str(&content) else {
+        return BTreeMap::new();
+    };
+
+    manifest
+        .items
+        .into_iter()
+        .filter_map(|item| {
+            let version = item.version?;
+            let version = version.trim().to_string();
+            if version.is_empty() {
+                None
+            } else {
+                Some((item.id, version))
+            }
+        })
+        .collect()
